const { maskSensitiveData: maskWithPatterns } = require('invisi-data')

const DEFAULT_MASK = '****'

function maskSensitiveData(value) {
  if (typeof value !== 'string') return value
  if (!isSensitiveDataMaskingEnabled()) return value

  try {
    return maskWithPatterns(value, getCustomPatterns())
  } catch (err) {
    return value
  }
}

function isSensitiveDataMaskingEnabled() {
  const config = global.maskSensitiveData

  if (config === true) return true
  if (!config) return false
  if (typeof config === 'string' || config instanceof RegExp) return true
  if (Array.isArray(config)) return config.length > 0
  if (typeof config !== 'object') return false
  if (config.enabled === false) return false
  if (config.enabled === true) return true

  return getPatternConfig(config).length > 0
}

function getCustomPatterns() {
  const config = global.maskSensitiveData
  return getPatternConfig(config)
    .map(toMaskingPattern)
    .filter(Boolean)
}

function getPatternConfig(config) {
  if (!config || config === true) return []
  if (typeof config === 'string' || config instanceof RegExp) return [config]
  if (Array.isArray(config)) return config
  if (typeof config !== 'object') return []

  const patterns = config.patterns || config.customPatterns || config.pattern
  if (!patterns) return []
  return Array.isArray(patterns) ? patterns : [patterns]
}

function toMaskingPattern(pattern) {
  if (!pattern) return null

  if (typeof pattern === 'string') {
    return {
      name: 'Custom sensitive data',
      regex: new RegExp(escapeRegExp(pattern), 'g'),
      mask: DEFAULT_MASK,
    }
  }

  if (pattern instanceof RegExp) {
    return {
      name: 'Custom sensitive data',
      regex: pattern,
      mask: DEFAULT_MASK,
    }
  }

  if (typeof pattern !== 'object') return null

  const regex = pattern.regex || pattern.pattern || pattern.match || pattern.value
  if (!regex) return null

  return {
    name: pattern.name || 'Custom sensitive data',
    regex: toRegExp(regex, Boolean(pattern.value && !pattern.regex && !pattern.pattern && !pattern.match)),
    mask: pattern.mask || pattern.replacement || pattern.replace || pattern.replaceWith || DEFAULT_MASK,
  }
}

function toRegExp(regex, escapeString = false) {
  if (regex instanceof RegExp) return regex
  if (typeof regex !== 'string') return regex
  if (escapeString) return new RegExp(escapeRegExp(regex), 'g')

  const match = regex.match(/^\/(.*)\/([a-z]*)$/)
  if (match) return new RegExp(match[1], match[2])

  return new RegExp(regex, 'g')
}

function escapeRegExp(value) {
  return value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')
}

module.exports = {
  maskSensitiveData,
  isSensitiveDataMaskingEnabled,
}

