cd /workspace/CodeceptJS && node - <<'NODE'
const assert = require('assert')
const output = require('./lib/output')
const Step = require('./lib/step')
const { maskSensitiveData } = require('./lib/sensitiveData')
function capture(fn) {
  const calls = []
  const originalLog = console.log
  console.log = (...args) => calls.push(args.map(String).join(' '))
  try { fn() } finally { console.log = originalLog }
  return calls.join('\n')
}
global.maskSensitiveData = { enabled: true, patterns: [{ regex: /john\.secret@example\.com/g, mask: '[email]' }, 'Jane Sensitive'] }
output.level(3)
const text = capture(() => {
  output.print('login john.secret@example.com')
  output.log('verbose Jane Sensitive')
  output.error('failed for john.secret@example.com')
  const step = new Step({}, 'fillField')
  step.args = ['email', 'john.secret@example.com']
  output.step(step)
})
assert(!text.includes('john.secret@example.com'))
assert(!text.includes('Jane Sensitive'))
assert(text.includes('[email]'))
assert(text.includes('****'))
global.maskSensitiveData = true
assert.equal(maskSensitiveData('{"password":"super-secret"}'), '{"password": "****"}')
global.maskSensitiveData = { enabled: false, patterns: [/super-secret/g] }
assert.equal(maskSensitiveData('super-secret'), 'super-secret')
NODE

